class Solution:
    def maxTaskAssign(self, tasks: List[int], workers: List[int], pills: int, strength: int) -> int:
        tasks.sort()
        workers.sort()
        def can_assign(k):
            worker_idx = len(workers) - 1
            pill_idx = pills
            for task_idx in range(k - 1, -1, -1):
                if workers[worker_idx] >= tasks[task_idx]:
                    worker_idx -= 1
                elif pill_idx > 0 and workers[worker_idx] + strength >= tasks[task_idx]:
                    pill_idx -= 1
                    worker_idx -= 1
                else:
                    return False
            return True
        left, right = 0, min(len(tasks), len(workers))
        while left < right:
            mid = (left + right + 1) // 2
            if can_assign(mid):
                left = mid
            else:
                right = mid - 1
        return left
